// Spread — array copy & merge
const a = [1, 2, 3];
const b = [4, 5];
const merged = [...a, ...b]; // [1, 2, 3, 4, 5]

// Spread — object copy & merge
const defaults = { theme: 'dark', lang: 'en' };
const user = { ...defaults, lang: 'fr', name: 'Alice' };
// { theme: 'dark', lang: 'fr', name: 'Alice' }

// Spread — pass array as arguments
const nums = [3, 1, 4, 1, 5];
console.log(Math.max(...nums)); // 5

// Rest — collect extra function arguments
function sum(first, ...rest) {
  return first + rest.reduce((a, b) => a + b, 0);
}
console.log(sum(1, 2, 3, 4)); // 10

// Rest — in destructuring
const [head, ...tail] = [10, 20, 30, 40];
console.log(head); // 10
console.log(tail); // [20, 30, 40]
